/**
 * Merges two pre-sorted arrays of integers into a single sorted array.
 * 
 * @param arr1 The first sorted array of integers.
 * @param size1 The size of the first array.
 * @param arr2 The second sorted array of integers.
 * @param size2 The size of the second array.
 * @return A dynamically allocated array containing the merged and sorted elements.
 *         The caller is responsible for freeing the memory.
 */
int* mergeSortedArrays(const int* arr1, int size1, const int* arr2, int size2) {
    int* merged = new int[size1 + size2];
    int i = 0, j = 0, k = 0;

    while (i < size1 && j < size2) {
        if (arr1[i] < arr2[j]) {
            merged[k++] = arr1[i++];
        } else {
            merged[k++] = arr2[j++];
        }
    }

    while (i < size1) {
        merged[k++] = arr1[i++];
    }

    while (j < size2) {
        merged[k++] = arr2[j++];
    }

    return merged;
}
