// AggregateMetrics calculates the average, maximum, and minimum values from a slice of integers.
// It takes a slice of integers as input and returns three integers representing
// the average (rounded to the nearest integer), maximum, and minimum values respectively.
func AggregateMetrics(numbers []int) (int, int, int) {
	if len(numbers) == 0 {
		return 0, 0, 0
	}

	sum := 0
	min := numbers[0]
	max := numbers[0]

	for _, num := range numbers {
		sum += num
		if num < min {
			min = num
		}
		if num > max {
			max = num
		}
	}

	avg := sum / len(numbers)
	return avg, max, min
}
