// CalculateInterest calculates the compound interest for a given principal amount, interest rate,
// time period in years, and the number of times interest is applied per year.
// Parameters:
//   - principal: the initial amount of money (must be positive)
//   - rate: the annual interest rate (must be positive)
//   - time: the time the money is invested for in years (must be positive)
//   - frequency: the number of times interest is compounded per year (must be positive)
// Returns:
//   - the calculated compound interest
//   - an error if any of the input values are invalid
func CalculateInterest(principal float64, rate float64, time float64, frequency int) (float64, error) {
    if principal <= 0 {
        return 0, fmt.Errorf("principal must be positive")
    }
    if rate <= 0 {
        return 0, fmt.Errorf("rate must be positive")
    }
    if time <= 0 {
        return 0, fmt.Errorf("time must be positive")
    }
    if frequency <= 0 {
        return 0, fmt.Errorf("frequency must be positive")
    }

    amount := principal * math.Pow(1 + (rate / float64(frequency)), float64(frequency) * time)
    interest := amount - principal
    return interest, nil
}
