// Function to calculate the nth Fibonacci number using iterative approach
int calculateFibonacci(int n) {
    // Handle base cases where n is 0 or 1
    if (n == 0) return 0;
    if (n == 1) return 1;

    // Initialize variables to store the previous two Fibonacci numbers
    int fibPrevPrev = 0;  // F(n-2)
    int fibPrev = 1;      // F(n-1)
    int fibCurrent;       // F(n)

    // Iterate from 2 to n to compute F(n)
    for (int i = 2; i <= n; ++i) {
        // Calculate current Fibonacci number as sum of previous two
        fibCurrent = fibPrev + fibPrevPrev;
        // Update previous two numbers for next iteration
        fibPrevPrev = fibPrev;
        fibPrev = fibCurrent;
    }

    // Return the nth Fibonacci number
    return fibCurrent;
}
