// ProcessCSVData reads data from a CSV file and processes it based on the given condition.
// Expected behavior based on processCondition:
//   - "uppercase": Converts all string fields to uppercase.
//   - "lowercase": Converts all string fields to lowercase.
//   - "trim": Trims whitespace from all string fields.
//   - Default: Returns the data as-is without modification.
// The function checks if the file exists and is readable before processing.
func ProcessCSVData(filePath string, processCondition string) ([][]string, error) {
	// Check if file exists and is readable
	if _, err := os.Stat(filePath); os.IsNotExist(err) {
		return nil, fmt.Errorf("file does not exist: %s", filePath)
	}

	file, err := os.Open(filePath)
	if err != nil {
		return nil, fmt.Errorf("failed to open file: %v", err)
	}
	defer file.Close()

	reader := csv.NewReader(file)
	records, err := reader.ReadAll()
	if err != nil {
		return nil, fmt.Errorf("failed to read CSV data: %v", err)
	}

	// Process data based on condition
	for i, row := range records {
		for j, field := range row {
			switch processCondition {
			case "uppercase":
				records[i][j] = strings.ToUpper(field)
			case "lowercase":
				records[i][j] = strings.ToLower(field)
			case "trim":
				records[i][j] = strings.TrimSpace(field)
			}
		}
	}

	return records, nil
}
