/*
compressString takes a string input and compresses it by counting the consecutive repeats of each character.
For example, "aabcccccaaa" becomes "a2b1c5a3". If the compressed string is longer than the original,
the function returns the original string.

Parameters:
- s: The input string to be compressed.

Returns:
- The compressed string if it is shorter than the original, otherwise the original string.
*/
func compressString(s string) string {
	if len(s) == 0 {
		return s
	}

	var compressed strings.Builder
	currentChar := s[0]
	count := 1

	for i := 1; i < len(s); i++ {
		if s[i] == currentChar {
			count++
		} else {
			compressed.WriteByte(currentChar)
			compressed.WriteString(strconv.Itoa(count))
			currentChar = s[i]
			count = 1
		}
	}
	compressed.WriteByte(currentChar)
	compressed.WriteString(strconv.Itoa(count))

	if compressed.Len() >= len(s) {
		return s
	}
	return compressed.String()
}
