/// A struct to hold the computed statistics (mean, median, mode) of a list of integers.
#[derive(Debug, PartialEq)]
pub struct Statistics {
    pub mean: f64,
    pub median: f64,
    pub mode: Option<i32>,
}

/// Computes the mean, median, and mode of a given list of integers.
///
/// # Parameters
/// - `numbers`: A slice of integers (`&[i32]`) for which statistics are computed.
///
/// # Returns
/// A `Statistics` struct containing:
/// - `mean`: The average value of the numbers (as `f64`).
/// - `median`: The middle value of the sorted list (as `f64`).
/// - `mode`: The most frequent value (as `Option<i32>`), or `None` if all values are unique.
///
/// # Examples
/// ```
/// let numbers = vec![1, 2, 2, 3, 4];
/// let stats = compute_stats(&numbers);
/// assert_eq!(stats.mean, 2.4);
/// assert_eq!(stats.median, 2.0);
/// assert_eq!(stats.mode, Some(2));
/// ```
pub fn compute_stats(numbers: &[i32]) -> Statistics {
    if numbers.is_empty() {
        return Statistics {
            mean: 0.0,
            median: 0.0,
            mode: None,
        };
    }

    let mean = compute_mean(numbers);
    let median = compute_median(numbers);
    let mode = compute_mode(numbers);

    Statistics { mean, median, mode }
}

fn compute_mean(numbers: &[i32]) -> f64 {
    let sum: i32 = numbers.iter().sum();
    sum as f64 / numbers.len() as f64
}

fn compute_median(numbers: &[i32]) -> f64 {
    let mut sorted = numbers.to_vec();
    sorted.sort();

    let len = sorted.len();
    if len % 2 == 0 {
        let mid = len / 2;
        (sorted[mid - 1] as f64 + sorted[mid] as f64) / 2.0
    } else {
        sorted[len / 2] as f64
    }
}

fn compute_mode(numbers: &[i32]) -> Option<i32> {
    use std::collections::HashMap;

    let mut frequency_map = HashMap::new();
    for &num in numbers {
        *frequency_map.entry(num).or_insert(0) += 1;
    }

    frequency_map
        .into_iter()
        .max_by_key(|&(_, count)| count)
        .and_then(|(num, count)| if count > 1 { Some(num) } else { None })
}
