// SumSlice calculates the sum of all integers in the provided slice.
// It returns the sum and an error if the sum exceeds the maximum value of int.
// Parameters:
//   nums - a slice of integers to sum
// Returns:
//   int - the computed sum (or partial sum if overflow occurs)
//   error - non-nil if overflow occurs
func SumSlice(nums []int) (int, error) {
	var sum int
	for _, num := range nums {
		if sum > 0 && num > 0 && sum > math.MaxInt-num {
			return sum, fmt.Errorf("integer overflow detected")
		}
		if sum < 0 && num < 0 && sum < math.MinInt-num {
			return sum, fmt.Errorf("integer overflow detected")
		}
		sum += num
	}
	return sum, nil
}
