/**
 * Computes the total stock for each unique product from a list of stock records.
 * Each record contains product_id, stock, and timestamp.
 * @return MutableMap<String, Int> where keys are product_ids and values are summed stocks.
 */
fun calculateStockSummary(stockRecords: List<Map<String, Any>>): MutableMap<String, Int> {
    val summary = mutableMapOf<String, Int>()
    for (record in stockRecords) {
        val productId = record["product_id"] as String
        val stock = record["stock"] as Int
        summary[productId] = (summary[productId] ?: 0) + stock
    }
    return summary
}
