// MaxSubArraySum calculates the maximum sum of any contiguous subarray within the input array.
// It implements Kadane's Algorithm to efficiently compute the result.
// Parameters:
//   nums: An array of integers to analyze.
// Returns:
//   The maximum sum of any contiguous subarray. Returns 0 if the array is empty.
//   If all numbers are negative, returns the highest single negative element.
func MaxSubArraySum(nums []int) int {
	if len(nums) == 0 {
		return 0
	}

	maxCurrent := nums[0]
	maxGlobal := nums[0]
	allNegative := nums[0] < 0

	for i := 1; i < len(nums); i++ {
		if nums[i] > maxCurrent+nums[i] {
			maxCurrent = nums[i]
		} else {
			maxCurrent += nums[i]
		}

		if maxCurrent > maxGlobal {
			maxGlobal = maxCurrent
		}

		if nums[i] >= 0 {
			allNegative = false
		} else if nums[i] > maxGlobal {
			maxGlobal = nums[i]
		}
	}

	if allNegative {
		return maxGlobal
	}

	return maxGlobal
}
