/**
 * Evaluates a mathematical expression given in Reverse Polish Notation (RPN).
 * The expression consists of integers and the four basic arithmetic operators (+, -, *, /) separated by spaces.
 * 
 * @param expression The RPN expression as a string.
 * @return The result of the evaluated expression.
 * @throws ArithmeticException If division by zero occurs.
 * @throws IllegalArgumentException If the expression is malformed (extra operators or insufficient operands).
 */
public static int evaluateRPNExpression(String expression) {
    // Note: Stack to hold operands for RPN evaluation
    Stack<Integer> stack = new Stack<>();

    // Note: Split the expression into tokens by spaces
    String[] tokens = expression.split(" ");

    for (String token : tokens) {
        if (token.matches("-?\\d+")) { // Note: Check if token is an integer (positive or negative)
            stack.push(Integer.parseInt(token));
        } else { // Note: Token is an operator
            if (stack.size() < 2) {
                throw new IllegalArgumentException("Insufficient operands for operator: " + token);
            }

            int operand2 = stack.pop();
            int operand1 = stack.pop();

            switch (token) {
                case "+":
                    stack.push(operand1 + operand2);
                    break;
                case "-":
                    stack.push(operand1 - operand2);
                    break;
                case "*":
                    stack.push(operand1 * operand2);
                    break;
                case "/":
                    if (operand2 == 0) {
                        throw new ArithmeticException("Division by zero");
                    }
                    stack.push(operand1 / operand2);
                    break;
                default:
                    throw new IllegalArgumentException("Invalid operator: " + token);
            }
        }
    }

    if (stack.size() != 1) {
        throw new IllegalArgumentException("Malformed expression: extra operands or insufficient operators");
    }

    return stack.pop();
}
